idioms.bad_example:
class Point:
    def __init__(self, x, y):
        self.x = x
        self.y = y

idioms.good_example:
@dataclass(frozen=True)
class Point:
    x: float
    y: float

idioms.bad_example:
def add_item(item, items=[]):
    items.append(item)
    return items

idioms.good_example:
def add_item(item, items: list | None = None) -> list:
    if items is None:
        items = []
    items.append(item)
    return items

idioms.bad_example:
def get_lines(path):
    result = []
    with open(path) as f:
        for line in f:
            result.append(line.strip())
    return result

idioms.good_example:
def get_lines(path):
    with open(path) as f:
        for line in f:
            yield line.strip()

idioms.bad_example:
class User:
    def get_name(self): return self._name
    def set_name(self, v): self._name = v

idioms.good_example:
class User:
    @property
    def name(self) -> str: return self._name
    @name.setter
    def name(self, v: str): self._name = v
